import { createServer } from '../src/server';
import http from 'http';

function httpGet(url: string): Promise<{ statusCode: number | null; body: string; headers: http.IncomingHttpHeaders }> {
  return new Promise((resolve, reject) => {
    http.get(url, (res) => {
      const chunks: Buffer[] = [];
      res.on('data', (c) => chunks.push(Buffer.from(c)));
      res.on('end', () => {
        const body = Buffer.concat(chunks).toString('utf8');
        resolve({ statusCode: res.statusCode, body, headers: res.headers });
      });
    }).on('error', (err) => reject(err));
  });
}

describe('hello03 server', () => {
  let server: http.Server;
  let baseUrl: string;

  beforeAll((done) => {
    server = createServer();
    server.listen(0, () => {
      // @ts-ignore - address() type can be string or object depending on platform
      const address = server.address();
      if (address && typeof address === 'object') {
        baseUrl = `http://127.0.0.1:${address.port}`;
      } else {
        baseUrl = 'http://127.0.0.1:3000';
      }
      done();
    });
  });

  afterAll((done) => {
    server.close(() => done());
  });

  test('GET / returns "Hello 03"', async () => {
    const res = await httpGet(baseUrl + '/');
    expect(res.statusCode).toBe(200);
    expect(res.body).toBe('Hello 03');
    expect(res.headers['content-type']).toMatch(/text\/plain/);
  });

  test('GET /not-found returns 404', async () => {
    const res = await httpGet(baseUrl + '/not-found');
    expect(res.statusCode).toBe(404);
    expect(res.body).toBe('Not Found');
  });
});


